am:["\u041C\u043E\u0440\u043E\u0436\u0435\u043D\u043E\u0435 \u2014 \u0445\u043E\u043B\u043E\u0434\u043D\u044B\u0439 \u043A\u0430\u0439\u0444. \u0421\u043B\u0430\u0434\u043A\u043E \u0438 \u0447\u0435\u0441\u0442\u043D\u043E.","\u041C\u043E\u0437\u0433\u0438: \xAB\u0435\u0449\u0451 \u0448\u0430\u0440\u0438\u043A\xBB. \u042F: \xAB\u0434\u0430\u0432\u0430\u0439, \u0431\u0440\u043E\xBB.","\u041B\u0435\u0442\u043E\u043C \u2014 \u043B\u0435\u0433\u0435\u043D\u0434\u0430. \u041A\u0430\u0436\u0434\u044B\u0439 \u0434\u0435\u043D\u044C \u2014 \u0442\u043E\u0436\u0435 \u043A\u0430\u0439\u0444, \u0435\u0441\u043B\u0438 \u0447\u0435\u0441\u0442\u043D\u043E."],chocolate:["\u0428\u043E\u043A\u043E\u043B\u0430\u0434 \u2014 \u043A\u0430\u0439\u0444 \u043A \u0447\u0430\u044E. \u0414\u043E\u0444\u0430\u043C\u0438\u043D \u0432 \u0434\u0435\u043B\u0435.","\u0413\u043E\u0440\u044C\u043A\u0438\u0439? \u0421\u0442\u0438\u043B\u044C\u043D\u043E. \u041C\u043E\u043B\u043E\u0447\u043D\u044B\u0439? \u0412\u043A\u0443\u0441\u043D\u0435\u0435. \u0412\u044B\u0431\u043E\u0440 \u0437\u0430 \u0442\u043E\u0431\u043E\u0439, \u0431\u0440\u043E.","\u0414\u0432\u0430 \u043A\u0432\u0430\u0434\u0440\u0430\u0442\u0438\u043A\u0430 \u2014 \u043D\u043E\u0440\u043C. \u041F\u043B\u0438\u0442\u043A\u0443 \u2014 \u0443\u0432\u0430\u0436\u0430\u044E \u0441\u043C\u0435\u043B\u043E\u0441\u0442\u044C."],coffee:["\u041A\u043E\u0444\u0435 \u2014 \u0431\u043E\u0434\u0440\u0438\u0442 \u043C\u043E\u0437\u0433. \u0420\u0430\u0431\u043E\u0447\u0438\u0439 \u0434\u0432\u0438\u0436, \u0431\u0440\u043E.","\u0413\u043E\u0440\u044C\u043A\u043E, \u0447\u0435\u0441\u0442\u043D\u043E, \u0440\u0430\u0431\u043E\u0447\u0435. \u0421 \u0441\u0438\u0440\u043E\u043F\u043E\u043C \u2014 \u0443\u0436\u0435 \u043F\u0440\u0430\u0437\u0434\u043D\u0438\u043A.","\u041E\u0434\u043D\u0430 \u0447\u0430\u0448\u043A\u0430 \u2014 \u043E\u043A. \u0422\u0440\u0438 \u2014 \u0442\u044B \u043D\u0435 \u043A\u043E\u043B\u043E\u0431\u043E\u043A, \u0442\u044B \u0432\u0438\u0431\u0440\u0430\u0442\u043E\u0440."],water:["\u0412\u043E\u0434\u0430 \u2014 \u0431\u0430\u0437\u0430. \u0411\u0435\u0437 \u043D\u0435\u0451 \u044F \u043C\u044F\u0447\u0438\u043A \u0441 \u043C\u043E\u0440\u0449\u0438\u043D\u0430\u043C\u0438, \u043D\u0435 \u0448\u0443\u0447\u0443.","\u0427\u0438\u0441\u0442\u0430\u044F, \u0441\u043A\u0443\u0447\u043D\u0430\u044F, \u0433\u0435\u043D\u0438\u0430\u043B\u044C\u043D\u0430\u044F. \u0416\u0430\u0436\u0434\u0430 \u0443\u0445\u043E\u0434\u0438\u0442 \u2014 \u0443\u0432\u0430\u0436\u0435\u043D\u0438\u0435 \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442.","\u041B\u0443\u0447\u0448\u0438\u0439 \u043D\u0430\u043F\u0438\u0442\u043E\u043A, \u0435\u0441\u043B\u0438 \u043D\u0435 \u0441\u0447\u0438\u0442\u0430\u0442\u044C \u043C\u043E\u043B\u043E\u043A\u043E. \u0421\u0447\u0438\u0442\u0430\u0435\u043C? \u0422\u043E\u0433\u0434\u0430 \u0442\u043E\u043F-2."],milk:["\u041C\u043E\u043B\u043E\u043A\u043E \u2014 \u043A\u0430\u043B\u044C\u0446\u0438\u0439, \u0431\u0435\u043B\u043E\u043A, \u0434\u0435\u0442\u0441\u0442\u0432\u043E. \u041D\u043E\u0440\u043C \u0437\u0430\u0440\u044F\u0434 \u0431\u0435\u0437 \u0434\u0440\u0430\u043C\u044B.","\u0422\u0451\u043F\u043B\u043E\u0435 \u2014 \u0441\u043E\u043D \u043A\u043B\u043E\u043D\u0438\u0442. \u0425\u043E\u043B\u043E\u0434\u043D\u043E\u0435 \u2014 \u0441\u0432\u0435\u0436\u043E. \u041E\u0431\u0430 \u2014 \u0432 \u043F\u043B\u044E\u0441.","\u0411\u0430\u0431\u043A\u0430 \u0431\u044B \u0441\u043A\u0430\u0437\u0430\u043B\u0430 \xAB\u043F\u0435\u0439\xBB. \u042F \u0433\u043E\u0432\u043E\u0440\u044E \xAB\u043F\u0435\u0439, \u0431\u0440\u043E, \u044D\u0442\u043E \u043A\u0430\u0442\u0438\u0442\xBB."],juice:["\u0421\u043E\u043A \u2014 \u0444\u0440\u0443\u043A\u0442 \u0432 \u0441\u0442\u0430\u043A\u0430\u043D\u0435. \u0412\u043A\u0443\u0441\u043D\u043E, \u0431\u0440\u043E.","\u0412\u0438\u0442\u0430\u043C\u0438\u043D\u044B \u0435\u0441\u0442\u044C, \u0432\u043A\u0443\u0441 \u0442\u043E\u0436\u0435. \u0423\u0432\u0430\u0436\u0430\u044E.","\u041E\u0441\u0432\u0435\u0436\u0430\u0435\u0442, \u0431\u0440\u043E. \u041B\u0435\u0442\u043D\u0438\u0439 \u0434\u0432\u0438\u0436 \u0431\u0435\u0437 \u043F\u0430\u0444\u043E\u0441\u0430."],apple:["\u042F\u0431\u043B\u043E\u043A\u043E \u2014 \u0445\u0440\u0443\u0441\u0442, \u0441\u043A\u0430\u0437\u043A\u0430, \u0443\u0432\u0430\u0436\u0435\u043D\u0438\u0435.","\u041E\u0434\u043D\u043E \u0432 \u0434\u0435\u043D\u044C \u2014 \u043C\u0438\u0444, \u043D\u043E \u043F\u0430\u0440\u0443 \u2014 \u043D\u043E\u0440\u043C \u0434\u0432\u0438\u0436.","\u0421\u043B\u0430\u0434\u043A\u043E\u0435, \u043D\u043E \u0447\u0435\u0441\u0442\u043D\u043E\u0435. \u0417\u0443\u0431\u044B \u0440\u0430\u0434\u044B, \u043D\u0430\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u0435 \u0442\u043E\u0436\u0435."],banana:["\u0411\u0430\u043D\u0430\u043D \u2014 \u0431\u044B\u0441\u0442\u0440\u044B\u0439 \u0437\u0430\u0440\u044F\u0434, \u043A\u0430\u043B\u0438\u0439, \u0443\u0434\u043E\u0431\u043D\u043E. \u041F\u0435\u0440\u0435\u043A\u0443\u0441, \u0431\u0440\u043E.","\u041C\u044F\u0433\u043A\u0438\u0439, \u0441\u043B\u0430\u0434\u043A\u0438\u0439, \u0431\u0435\u0437 \u0444\u0430\u043D\u0430\u0442\u0438\u0437\u043C\u0430 \u2014 \u0442\u043E\u043F.","\u0416\u0451\u043B\u0442\u044B\u0439 \u0434\u0440\u0443\u0433. \u041A\u0430\u0439\u0444 \u0431\u0435\u0437 \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0438\u0438."],broccoli:["\u0411\u0440\u043E\u043A\u043A\u043E\u043B\u0438 \u2014 \u0437\u0435\u043B\u0451\u043D\u044B\u0439 \u0431\u043E\u0441\u0441. \u0425\u0440\u0443\u0441\u0442\u0438\u0442, \u0443\u0432\u0430\u0436\u0430\u044E.","\u041C\u043E\u0436\u0435\u0442 \u043F\u0430\u0445\u043D\u0443\u0442\u044C \u0441\u0442\u0440\u0430\u043D\u043D\u043E, \u0437\u0430\u0442\u043E \u0432\u044B\u0433\u043B\u044F\u0434\u0438\u0442 \u0443\u043C\u043D\u043E.","\u042F \u043D\u0435 \u0444\u0430\u043D\u0430\u0442, \u043D\u043E \u0443\u0432\u0430\u0436\u0430\u044E. \u042D\u0442\u043E \u0440\u0435\u0434\u043A\u0438\u0439 \u0441\u043E\u044E\u0437."],salad:["\u0421\u0430\u043B\u0430\u0442 \u2014 \u043B\u0438\u0441\u0442\u044C\u044F \u0441 \u0430\u043C\u0431\u0438\u0446\u0438\u044F\u043C\u0438. \u041B\u0451\u0433\u043A\u0438\u0439, \u0436\u0438\u0432\u043E\u0439, \u0432 \u043F\u043B\u044E\u0441.","\u0417\u0435\u043B\u0435\u043D\u044C + \u043E\u0432\u043E\u0449\u0438 \u2014 \u0441\u0432\u0435\u0436\u0438\u0439 \u0434\u0432\u0438\u0436, \u0431\u0440\u043E.","\u0421\u0435\u0433\u043E\u0434\u043D\u044F \u2014 \u0441\u0430\u043B\u0430\u0442. \u0417\u0430\u0432\u0442\u0440\u0430 \u2014 \u0447\u0442\u043E \u0443\u0433\u043E\u0434\u043D\u043E. \u0416\u0438\u0432\u0451\u043C."],bread:["\u0425\u043B\u0435\u0431 \u2014 \u043E\u0441\u043D\u043E\u0432\u0430. \u041D\u043E\u0440\u043C\u0430\u043B\u044C\u043D\u044B\u0439 \u043A\u0443\u0441\u043E\u043A \u2014 \u0441\u044B\u0442\u043E\u0441\u0442\u044C \u0431\u0435\u0437 \u0446\u0438\u0440\u043A\u0430.","\u0421\u0432\u0435\u0436\u0438\u0439 \u2014 \u043A\u0430\u0439\u0444. \u0421\u0443\u0445\u043E\u0439 \u2014 \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u0441\u0443\u043F, \u0431\u0440\u043E.","\u041A\u0443\u0441\u043E\u043A \u2014 \u0443\u0432\u0430\u0436\u0435\u043D\u0438\u0435 \u043A \u0436\u0438\u0437\u043D\u0438. \u0411\u0430\u0431\u043A\u0430 \u043E\u0434\u043E\u0431\u0440\u0438\u043B\u0430 \u0431\u044B."],cheese:["\u0421\u044B\u0440 \u2014 \u0431\u0435\u043B\u043E\u043A, \u043A\u0430\u0439\u0444, \u0443\u0432\u0430\u0436\u0435\u043D\u0438\u0435. \u0421\u044B\u0440\u043D\u044B\u0439 \u0434\u0432\u0438\u0436.","\u041F\u043B\u0430\u0432\u043B\u0435\u043D\u044B\u0439 \u2014 \u0443\u0434\u043E\u0431\u043D\u043E. \u041D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u0439 \u2014 \u0443\u0432\u0430\u0436\u0435\u043D\u0438\u0435.","\u041D\u0430 \u0431\u0443\u0442\u0435\u0440\u0431\u0440\u043E\u0434 \u2014 \u043D\u043E\u0440\u043C. \u0412\u0435\u0434\u0440\u043E\u043C \u2014 \u0443\u0436\u0435 \u043A\u0438\u043D\u043E."],